internal final class UBSOutboundInterfaceStockContractUIBuilder extends SysOperationUIBuilder
{
    private UBSOutboundInterfaceStockContract contract;

    DataAreaId legalEntity;
    TransDate periodDate;

    private DialogField dialogLegalEntity;
    private DialogField dialogPeriodDate;

}

Method.Source:
    [Hookable(false)]
    public void build()
    {
        super();

        Dialog dialogLocal = dialog as Dialog;

        dialogLegalEntity = dialog.addFieldValue(extendedtypestr(DataAreaId), legalEntity, "@SYS13342");
        dialogPeriodDate = dialog.addFieldValue(extendedtypestr(TransDate), periodDate, "@SYS7402");
    }

    [Hookable(false)]
    public void postRun()
    {
        super();

        dialogLegalEntity.registerOverrideMethod(
            methodStr(FormStringControl, lookup),
            methodStr(UBSOutboundInterfaceStockContractUIBuilder, dialogLegalEntityLookup),
            this);
    }

    private void dialogLegalEntityLookup(FormControl _formControl)
    {
        // Create an instance of SysReferenceTableLookup with the "lookup table" and
        // the current form control.
        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(CompanyInfo), _formControl);

        // Add fields to be shown in the lookup form.
        sysTableLookup.addLookupfield(fieldNum(CompanyInfo, DataArea));
        sysTableLookup.addLookupfield(fieldNum(CompanyInfo, Name));

        // Create the QueryBuildDataSource.
        Query query = new Query();
        QueryBuildDataSource queryBuildDataSource = query.addDataSource(tableNum(CompanyInfo));

        queryBuildDataSource.addRange(fieldNum(CompanyInfo,UBSInterfaceTarget)).value(queryValue(UBSInterfaceTarget::Sage));

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
    }

    private UBSOutboundInterfaceStockContract getContract()
    {
        if (contract == null)
        {
            contract = this.dataContractObject() as UBSOutboundInterfaceStockContract;
        }

        return contract;
    }

    public void getFromDialog()
    {
        super();

        contract = this.getContract();
        contract.parmPeriodDate(dialogPeriodDate.value());
        contract.parmLegalEntity(dialogLegalEntity.value());
    }
